import React from 'react';
import { useDispatch } from 'react-redux';
import { fetchAllSchedules  } from '../redux/slices/rasps';

export const Rasp = () => {
	const dispatch = useDispatch();
	const { items, status } = useSelector((state) => state.rasps);

	useEffect(() => {
	  // Sayfa yüklendiğinde tüm programları getir
	  dispatch(fetchAllSchedules());
	}, [dispatch]);

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
      <strong className="text-gray-700 font-medium">Расписания</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Время</th>
              <th>День</th>
              <th>Предмет</th>
              <th>Группа</th>
              <th>Преподаватель</th>
              <th>Курс</th>
              <th>Кабинет</th>
              {isEditable && <th>Actions</th>}
            </tr>
          </thead>
          <tbody>
		  {items.map((item) => (
              <tr key={item._id}>
                <td>{item._id}</td>
                <td>{item.time && item.time.time}</td>
                <td>{item.day && item.day.day}</td>
                {/* Diğer kolonlar eklenebilir */}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Rasp;
